using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;

// --- Tool definitions --------------------------------------------------------

/// <summary>Tools the research agent can invoke during its investigation.</summary>
static class ResearchTools
{
    // In-memory scratchpad shared across invocations.
    private static readonly List<string> _notes = [];
    private static readonly HttpClient _http = new();

    [Description("Search the web for a query and return a list of result snippets. " +
                 "Use this to discover information about a topic.")]
    public static async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        // Uses the DuckDuckGo Instant Answer API (no key required).
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            using var response = await _http.GetAsync(url);
            response.EnsureSuccessStatusCode();
            var doc = await response.Content.ReadFromJsonAsync<JsonElement>();

            var results = new List<string>();

            // Abstract (main summary)
            var abstractText = doc.GetProperty("Abstract").GetString();
            var abstractSource = doc.GetProperty("AbstractSource").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
                results.Add($"[{abstractSource}] {abstractText}");

            // Related topics
            if (doc.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text))
                        results.Add(text.GetString()!);
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : "No results found. Try rephrasing or breaking the query into smaller parts.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note. Use this to record key findings as you discover them.")]
    public static string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public static string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n",
            _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

// --- Agent loop --------------------------------------------------------------

Console.WriteLine("🔬  Research Agent");
Console.WriteLine(new string('─', 50));

// Resolve the model endpoint – supports Azure OpenAI and OpenAI.
var endpoint = Environment.GetEnvironmentVariable("AZURE_OPENAI_ENDPOINT");
var apiKey   = Environment.GetEnvironmentVariable("AZURE_OPENAI_API_KEY")
            ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
            ?? throw new InvalidOperationException(
                   "Set AZURE_OPENAI_API_KEY or OPENAI_API_KEY.");
var model    = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";

IChatClient innerClient;

if (!string.IsNullOrEmpty(endpoint))
{
    // Azure OpenAI
    var azureClient = new Azure.AI.OpenAI.AzureOpenAIClient(
        new Uri(endpoint),
        new System.ClientModel.ApiKeyCredential(apiKey));
    innerClient = azureClient.GetChatClient(model).AsIChatClient();
}
else
{
    // OpenAI
    var openAIClient = new OpenAI.OpenAIClient(apiKey);
    innerClient = openAIClient.GetChatClient(model).AsIChatClient();
}

// Wrap with automatic function-calling support.
IChatClient chatClient = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

var tools = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(ResearchTools.SearchWeb),
        AIFunctionFactory.Create(ResearchTools.SaveNote),
        AIFunctionFactory.Create(ResearchTools.GetNotes),
    ],
};

var systemPrompt = """
    You are a research agent. Your goal is to thoroughly research a topic the user
    provides using the tools at your disposal.

    Workflow:
    1. Break the topic into 2-3 focused sub-queries.
    2. Use SearchWeb for each sub-query to gather information.
    3. Use SaveNote to record the most important findings as you go.
    4. After gathering enough information, use GetNotes to review everything.
    5. Provide a well-structured summary with key facts, organized under headings.

    Be thorough but concise. Cite sources when available.
    """;

var history = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
};

Console.Write("\nEnter a research topic (or 'quit' to exit): ");

while (Console.ReadLine() is { } input)
{
    input = input.Trim();
    if (string.IsNullOrEmpty(input)) { Console.Write("\n> "); continue; }
    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase)) break;

    history.Add(new ChatMessage(ChatRole.User, $"Research the following topic: {input}"));

    Console.WriteLine("\n⏳ Researching… (the agent may make several tool calls)\n");

    var response = await chatClient.GetResponseAsync(history, tools);

    // Append assistant response to history for multi-turn conversations.
    foreach (var msg in response.Messages)
        history.Add(msg);

    // Print only the final assistant text.
    var finalText = response.Messages
        .Where(m => m.Role == ChatRole.Assistant && m.Text is not null)
        .Select(m => m.Text)
        .LastOrDefault();

    Console.WriteLine(finalText ?? "(no response)");
    Console.Write("\n> ");
}

